package com.b2b.ecommerce.service;

import com.b2b.ecommerce.service.model.Order;
import com.b2b.ecommerce.service.model.OrderConfirmation;
import com.b2b.ecommerce.service.model.OrderItem;
import javax.jws.WebService;
import java.util.logging.Logger;
import java.util.Locale;

@WebService(endpointInterface = "com.b2b.ecommerce.service.OrderProcessingService",
            serviceName = "OrderProcessingService",
            portName = "OrderProcessingPort",
            targetNamespace = "http://b2b.ecommerce.com/orderservice")
public class OrderProcessingServiceImpl implements OrderProcessingService {

    private static final Logger LOGGER = Logger.getLogger(OrderProcessingServiceImpl.class.getName());

    @Override
    public OrderConfirmation processOrder(Order order) {
        LOGGER.info(String.format("Received order: %s for customer: %s",
                order != null ? order.getOrderId() : "N/A",
                order != null ? order.getCustomerId() : "N/A"));

        if (order == null || order.getOrderId() == null || order.getOrderId().trim().isEmpty() ||
            order.getCustomerId() == null || order.getCustomerId().trim().isEmpty() ||
            order.getItems() == null || order.getItems().isEmpty()) {
            LOGGER.warning("Order is null or contains invalid basic details (ID, Customer ID, or no items).");
            return new OrderConfirmation(
                order != null ? order.getOrderId() : "UNKNOWN_ORDER",
                0.0,
                "FAILED",
                "Order is empty or invalid: Missing order ID, customer ID, or items."
            );
        }

        double totalAmount = 0.0;
        boolean hasInvalidItem = false;

        for (OrderItem item : order.getItems()) {
            if (item.getQuantity() <= 0 || item.getUnitPrice() <= 0) {
                LOGGER.warning(String.format("Invalid item detected in order %s: Product %s - Quantity: %d, Unit Price: %.2f",
                                   order.getOrderId(), item.getProductId(), item.getQuantity(), item.getUnitPrice()));
                hasInvalidItem = true;
                break;
            }
            totalAmount += item.getQuantity() * item.getUnitPrice();
        }

        if (hasInvalidItem) {
            return new OrderConfirmation(
                order.getOrderId(),
                0.0,
                "FAILED",
                "Order contains items with invalid quantities or prices."
            );
        }

        LOGGER.info(String.format("Processing order %s for customer %s. Calculated total amount: %.2f",
                order.getOrderId(), order.getCustomerId(), totalAmount));

        // In a real-world scenario, this is where you would integrate with
        // a database, inventory management, payment gateway, etc.
        // For this example, we simply simulate successful processing.

        return new OrderConfirmation(
            order.getOrderId(),
            Double.parseDouble(String.format(Locale.US, "%.2f", totalAmount)), // Format to 2 decimal places for consistency
            "PROCESSED",
            "Order successfully processed and total amount calculated."
        );
    }
}
